🐍 Interview Questions — Searching
Q1. Search in Rotated Sorted Array
The array was sorted, then rotated at an unknown pivot. Find target in O(log n).
def search_rotated(nums, target):
lo, hi = 0, len(nums) - 1
while lo <= hi:
mid = (lo + hi) // 2
if nums[mid] == target: return mid
# figure out which half is sorted
if nums[lo] <= nums[mid]: # left half is sorted
if nums[lo] <= target < nums[mid]:
hi = mid - 1
else:
lo = mid + 1
else: # right half is sorted
if nums[mid] < target <= nums[hi]:
lo = mid + 1
else:
hi = mid - 1
return -1
Q2. Find Peak Element
def find_peak(nums):
lo, hi = 0, len(nums) - 1
while lo < hi:
mid = (lo + hi) // 2
if nums[mid] > nums[mid+1]:
hi = mid # peak is at mid or to the left
else:
lo = mid + 1 # peak is to the right
return lo

