Handles negative edges. Relax every edge V−1 times. One more pass: if anything still improves, there's a
negative cycle.
def bellman_ford(n, edges, src):
dist = [float('inf')]*n
dist[src] = 0
for _ in range(n-1):
for u, v, w in edges:
if dist[u] + w < dist[v]:
dist[v] = dist[u] + w
# cycle check
for u, v, w in edges:
if dist[u] + w < dist[v]:
return None # negative cycle
return dist
