11.7 Longest Increasing Subsequence (LIS)
# O(n^2) version — easy to derive
def lis(nums):
if not nums: return 0
dp = [1]*len(nums)
for i in range(len(nums)):
for j in range(i):
if nums[j] < nums[i]:
dp[i] = max(dp[i], dp[j]+1)
return max(dp)

# O(n log n) version — patience sorting
import bisect
def lis_fast(nums):
tails = []
for x in nums:
i = bisect.bisect_left(tails, x)
if i == len(tails): tails.append(x)
else: tails[i] = x
return len(tails)
